import numpy as np

def clip_grad_norm(grads: list[np.ndarray], max_norm: float) -> float:
    total_norm_sq = sum(np.sum(g ** 2) for g in grads)
    global_norm = float(np.sqrt(total_norm_sq))
    if global_norm > max_norm:
        scale = max_norm / global_norm
        for g in grads:
            g *= scale
    return global_norm
